        my_vtype = NDS_VEC_MAKE_VTYPE(NDS_VEC_VTYPE_SEW_VAL_E8, NDS_VEC_VTYPE_LMUL_VAL_M4);
    }

    long vl, maxvl_perf_vg;
    long size2 = size;

    NDS_VEC_VSETVL(maxvl_perf_vg, reg_x0, my_vtype);
    long maxvl_per_loop = maxvl_perf_vg << 2;

    /* 2-iteration software pipeline: overlap stores of iter N-1 with loads of iter N. */
    if (size2 >= (maxvl_per_loop << 1))
    {
        /* Prologue: load iter 0 into v0/v8/v16/v24 and apply vmax. */
        q7_t * p_in2 = in_out  + maxvl_perf_vg;
        NDS_VEC_VLE8_V(NDS_VEC_V0, in_out);
        q7_t * p_in3 = p_in2   + maxvl_perf_vg;
        NDS_VEC_VLE8_V(NDS_VEC_V8, p_in2);
        q7_t * p_in4 = p_in3   + maxvl_perf_vg;
        NDS_VEC_VLE8_V(NDS_VEC_V16, p_in3);
        NDS_VEC_VLE8_V(NDS_VEC_V24, p_in4);
        NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VMAX_VX(NDS_VEC_V8, NDS_VEC_V8, 0);
        NDS_VEC_VMAX_VX(NDS_VEC_V16, NDS_VEC_V16, 0);
        NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, 0);

        /* Pipelined body: store iter N-1 from v0..v24, then load iter N into the
           same registers and vmax. Stores and subsequent loads drain through the
           VLSU with overlap across iterations. */
        while (size2 >= (maxvl_per_loop << 1))
        {
            q7_t * s_in2 = in_out + maxvl_perf_vg;
            q7_t * s_in3 = s_in2  + maxvl_perf_vg;
            q7_t * s_in4 = s_in3  + maxvl_perf_vg;
            q7_t * l_in1 = in_out + maxvl_per_loop;
            q7_t * l_in2 = l_in1  + maxvl_perf_vg;
            q7_t * l_in3 = l_in2  + maxvl_perf_vg;
            q7_t * l_in4 = l_in3  + maxvl_perf_vg;

            NDS_VEC_VSE8_V(NDS_VEC_V0, in_out);
            NDS_VEC_VSE8_V(NDS_VEC_V8, s_in2);
            NDS_VEC_VSE8_V(NDS_VEC_V16, s_in3);
            NDS_VEC_VSE8_V(NDS_VEC_V24, s_in4);

            NDS_VEC_VLE8_V(NDS_VEC_V0, l_in1);
            NDS_VEC_VLE8_V(NDS_VEC_V8, l_in2);
            NDS_VEC_VLE8_V(NDS_VEC_V16, l_in3);
            NDS_VEC_VLE8_V(NDS_VEC_V24, l_in4);

            NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VMAX_VX(NDS_VEC_V8, NDS_VEC_V8, 0);
            NDS_VEC_VMAX_VX(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, 0);

            in_out += maxvl_per_loop;
            size2  -= maxvl_per_loop;
        }

        /* Epilogue: store the last pipelined iter still held in v0..v24. */
        q7_t * e_in2 = in_out + maxvl_perf_vg;
        q7_t * e_in3 = e_in2  + maxvl_perf_vg;
        q7_t * e_in4 = e_in3  + maxvl_perf_vg;
        NDS_VEC_VSE8_V(NDS_VEC_V0, in_out);
        NDS_VEC_VSE8_V(NDS_VEC_V8, e_in2);
        NDS_VEC_VSE8_V(NDS_VEC_V16, e_in3);
        NDS_VEC_VSE8_V(NDS_VEC_V24, e_in4);
        in_out += maxvl_per_loop;
        size2  -= maxvl_per_loop;
    }

    /* Fallback for a single remaining main-loop block (size2 in [maxvl_per_loop, 2*maxvl_per_loop)). */
    while (size2 >= maxvl_per_loop)
    {
        q7_t * in_out2 = in_out  + maxvl_perf_vg;
        NDS_VEC_VLE8_V(NDS_VEC_V0, in_out);
        q7_t * in_out3 = in_out2 + maxvl_perf_vg;
        NDS_VEC_VLE8_V(NDS_VEC_V8, in_out2);
        q7_t * in_out4 = in_out3 + maxvl_perf_vg;
        NDS_VEC_VLE8_V(NDS_VEC_V16, in_out3);
        NDS_VEC_VLE8_V(NDS_VEC_V24, in_out4);
        NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VMAX_VX(NDS_VEC_V8, NDS_VEC_V8, 0);
        NDS_VEC_VMAX_VX(NDS_VEC_V16, NDS_VEC_V16, 0);
        NDS_VEC_VMAX_VX(NDS_VEC_V24, NDS_VEC_V24, 0);
        NDS_VEC_VSE8_V(NDS_VEC_V0, in_out);
        in_out += maxvl_per_loop;
        NDS_VEC_VSE8_V(NDS_VEC_V8, in_out2);
        size2 -= maxvl_per_loop;
        NDS_VEC_VSE8_V(NDS_VEC_V16, in_out3);
        NDS_VEC_VSE8_V(NDS_VEC_V24, in_out4);
    }

    while (size2 > 0)
    {
        NDS_VEC_VSETVL(vl, size2, my_vtype);
        NDS_VEC_VLE8_V(NDS_VEC_V0, in_out);
        size2 -= vl;
        NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VSE8_V(NDS_VEC_V0, in_out);
        in_out += vl;
    }
